 30	int decode_protocol_configuration_options(ProtocolConfigurationOptions *protocolconfigurationoptions, uint8_t iei, uint8_t *buffer, uint32_t len)
 31	{
 32	  uint32_t decoded = 0;
 33	  uint8_t ielen = 0;
 34	  int decode_result;
 35	
 36	  if (iei > 0) {
 37	    CHECK_IEI_DECODER(iei, *buffer);
 38	    decoded++;
 39	  }
 40	
 41	  ielen = *(buffer + decoded);
 42	  decoded++;
 43	  CHECK_LENGTH_DECODER(len - decoded, ielen);
 44	
 45	  if (((*(buffer + decoded) >> 7) & 0x1) != 1) {
 46	    errorCodeDecoder = TLV_DECODE_VALUE_DOESNT_MATCH;
 47	    return TLV_DECODE_VALUE_DOESNT_MATCH;
 48	  }
 49	
 50	  /* Bits 7 to 4 of octet 3 are spare, read as 0 */
 51	  if (((*(buffer + decoded) & 0x78) >> 3) != 0) {
 52	    errorCodeDecoder = TLV_DECODE_VALUE_DOESNT_MATCH;
 53	    return TLV_DECODE_VALUE_DOESNT_MATCH;
 54	  }
 55	
 56	  protocolconfigurationoptions->configurationprotol = (*(buffer + decoded) >> 1) & 0x7;
 57	  decoded++;
 58	
 59	  //IES_DECODE_U16(protocolconfigurationoptions->protocolid, *(buffer + decoded));
 60	  protocolconfigurationoptions->num_protocol_id_or_container_id = 0;
 61	  while ((len - decoded) > 0) {
 62	    IES_DECODE_U16(buffer, decoded, protocolconfigurationoptions->protocolid[protocolconfigurationoptions->num_protocol_id_or_container_id]);
 63	    DECODE_U8(buffer + decoded, protocolconfigurationoptions->lengthofprotocolid[protocolconfigurationoptions->num_protocol_id_or_container_id], decoded);
 64	
 65	    if (protocolconfigurationoptions->lengthofprotocolid[protocolconfigurationoptions->num_protocol_id_or_container_id] > 0) {
 66	      if ((decode_result = decode_octet_string(&protocolconfigurationoptions->protocolidcontents[protocolconfigurationoptions->num_protocol_id_or_container_id],
 67	                         protocolconfigurationoptions->lengthofprotocolid[protocolconfigurationoptions->num_protocol_id_or_container_id], buffer + decoded, len - decoded)) < 0) {
 68	        return decode_result;
 69	      } else {
 70	        decoded += decode_result;
 71	      }
 72	    } else {
 73	      protocolconfigurationoptions->protocolidcontents[protocolconfigurationoptions->num_protocol_id_or_container_id].length = 0;
 74	      protocolconfigurationoptions->protocolidcontents[protocolconfigurationoptions->num_protocol_id_or_container_id].value = NULL;
 75	    }
 76	    protocolconfigurationoptions->num_protocol_id_or_container_id += 1;
 77	  }
 78	
 79	#if defined (NAS_DEBUG)
 80	  dump_protocol_configuration_options_xml(protocolconfigurationoptions, iei);
 81	#endif
 82	  return decoded;
 83	}
 84	int encode_protocol_configuration_options(ProtocolConfigurationOptions *protocolconfigurationoptions, uint8_t iei, uint8_t *buffer, uint32_t len)
 85	{
 86	  uint8_t *lenPtr;
 87	  uint8_t  num_protocol_id_or_container_id = 0;
 88	  uint32_t encoded = 0;
 89	  int encode_result;
 90	  /* Checking IEI and pointer */
 91	  CHECK_PDU_POINTER_AND_LENGTH_ENCODER(buffer, PROTOCOL_CONFIGURATION_OPTIONS_MINIMUM_LENGTH, len);
 92	#if defined (NAS_DEBUG)
 93	  dump_protocol_configuration_options_xml(protocolconfigurationoptions, iei);
 94	#endif
 95	
 96	  if (iei > 0) {
 97	    *buffer = iei;
 98	    encoded++;
 99	  }
100	
101	  lenPtr  = (buffer + encoded);
102	  encoded ++;
103	  *(buffer + encoded) = 0x00 | (1 << 7) |
104	                        (protocolconfigurationoptions->configurationprotol & 0x7);
105	  encoded++;
106	
107	  while (num_protocol_id_or_container_id < protocolconfigurationoptions->num_protocol_id_or_container_id) {
108	
109	    IES_ENCODE_U16(buffer, encoded, protocolconfigurationoptions->protocolid[num_protocol_id_or_container_id]);
110	    *(buffer + encoded) = protocolconfigurationoptions->lengthofprotocolid[num_protocol_id_or_container_id];
111	    encoded++;
112	
113	    if ((encode_result = encode_octet_string(&protocolconfigurationoptions->protocolidcontents[num_protocol_id_or_container_id],
114	    		buffer + encoded,
115	    		len - encoded)) < 0)
116	      return encode_result;
117	    else
118	      encoded += encode_result;
119	
120	    num_protocol_id_or_container_id += 1;
121	  }
122	  *lenPtr = encoded - 1 - ((iei > 0) ? 1 : 0);
123	  return encoded;
124	}
125	
126	void dump_protocol_configuration_options_xml(ProtocolConfigurationOptions *protocolconfigurationoptions, uint8_t iei)
127	{
128	  int   i;
129	  printf("<Protocol Configuration Options>\n");
130	
131	  if (iei > 0)
132	    /* Don't display IEI if = 0 */
133	    printf("    <IEI>0x%X</IEI>\n", iei);
134	
135	  printf("    <Configuration protol>%u</Configuration protol>\n", protocolconfigurationoptions->configurationprotol);
136	  i = 0;
137	  while (i < protocolconfigurationoptions->num_protocol_id_or_container_id) {
138	    printf("        <Protocol ID>%u</Protocol ID>\n", protocolconfigurationoptions->protocolid[i]);
139	    printf("        <Length of protocol ID>%u</Length of protocol ID>\n", protocolconfigurationoptions->lengthofprotocolid[i]);
140	    printf("        %s",dump_octet_string_xml(&protocolconfigurationoptions->protocolidcontents[i]));
141	    i++;
142	  }
143	  printf("</Protocol Configuration Options>\n");
144	}
